tinymce.Resource.add("tinymce.html-i18n.help-keynav.uk",`<h1>\u041F\u043E\u0447\u0430\u0442\u043E\u043A \u0440\u043E\u0431\u043E\u0442\u0438 \u0437 \u043D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u0454\u044E \u0437\u0430 \u0434\u043E\u043F\u043E\u043C\u043E\u0433\u043E\u044E \u043A\u043B\u0430\u0432\u0456\u0430\u0442\u0443\u0440\u0438</h1>

<dl>
  <dt>\u0424\u043E\u043A\u0443\u0441 \u043D\u0430 \u0440\u044F\u0434\u043E\u043A \u043C\u0435\u043D\u044E</dt>
  <dd>Windows \u0430\u0431\u043E Linux: Alt+F9</dd>
  <dd>macOS: &#x2325;F9</dd>
  <dt>\u0424\u043E\u043A\u0443\u0441 \u043D\u0430 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432</dt>
  <dd>Windows \u0430\u0431\u043E Linux: Alt+F10</dd>
  <dd>macOS: &#x2325;F10</dd>
  <dt>\u0424\u043E\u043A\u0443\u0441 \u043D\u0430 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B"</dt>
  <dd>Windows \u0430\u0431\u043E Linux: Alt+F11</dd>
  <dd>macOS: &#x2325;F11</dd>
  <dt>\u0424\u043E\u043A\u0443\u0441 \u043D\u0430 \u0441\u043F\u043E\u0432\u0456\u0449\u0435\u043D\u043D\u044F</dt>
  <dd>Windows \u0430\u0431\u043E Linux: Alt+F12</dd>
  <dd>macOS: &#x2325;F12</dd>
  <dt>\u0424\u043E\u043A\u0443\u0441 \u043D\u0430 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u043D\u0456\u0439 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432</dt>
  <dd>Windows, Linux \u0430\u0431\u043E macOS: Ctrl+F9</dd>
</dl>

<p>\u041D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u044F \u043F\u043E\u0447\u043D\u0435\u0442\u044C\u0441\u044F \u0437 \u043F\u0435\u0440\u0448\u043E\u0433\u043E \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430, \u044F\u043A\u0438\u0439 \u0431\u0443\u0434\u0435 \u0432\u0438\u0434\u0456\u043B\u0435\u043D\u043E \u0430\u0431\u043E \u043F\u0456\u0434\u043A\u0440\u0435\u0441\u043B\u0435\u043D\u043E \u0432 \u0440\u0430\u0437\u0456, \u044F\u043A\u0449\u043E \u043F\u0435\u0440\u0448\u0438\u0439 \u0435\u043B\u0435\u043C\u0435\u043D\u0442 \u0437\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u0432
  \u0448\u043B\u044F\u0445\u0443 \u0434\u043E \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B".</p>

<h1>\u041D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u044F \u043C\u0456\u0436 \u0440\u043E\u0437\u0434\u0456\u043B\u0430\u043C\u0438 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430</h1>

<p>\u0429\u043E\u0431 \u043F\u0435\u0440\u0435\u0439\u0442\u0438 \u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0440\u043E\u0437\u0434\u0456\u043B\u0443 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u0434\u043E \u043D\u0430\u0441\u0442\u0443\u043F\u043D\u043E\u0433\u043E \u0440\u043E\u0437\u0434\u0456\u043B\u0443, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u043A\u043B\u0430\u0432\u0456\u0448\u0443 <strong>Tab</strong>.</p>

<p>\u0429\u043E\u0431 \u043F\u0435\u0440\u0435\u0439\u0442\u0438 \u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0440\u043E\u0437\u0434\u0456\u043B\u0443 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u0434\u043E \u043F\u043E\u043F\u0435\u0440\u0435\u0434\u043D\u044C\u043E\u0433\u043E \u0440\u043E\u0437\u0434\u0456\u043B\u0443, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u0441\u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044F \u043A\u043B\u0430\u0432\u0456\u0448 <strong>Shift+Tab</strong>.</p>

<p>\u041F\u043E\u0440\u044F\u0434\u043E\u043A <strong>\u0412\u043A\u043B\u0430\u0434\u043E\u043A</strong> \u0446\u0438\u0445 \u0440\u043E\u0437\u0434\u0456\u043B\u0456\u0432 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u0442\u0430\u043A\u0438\u0439:</p>

<ol>
  <li>\u0420\u044F\u0434\u043E\u043A \u043C\u0435\u043D\u044E</li>
  <li>\u041A\u043E\u0436\u043D\u0430 \u0433\u0440\u0443\u043F\u0430 \u043F\u0430\u043D\u0435\u043B\u0435\u0439 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432</li>
  <li>\u0411\u0456\u0447\u043D\u0430 \u043F\u0430\u043D\u0435\u043B\u044C</li>
  <li>\u0428\u043B\u044F\u0445 \u0434\u043E \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0456\u0432 \u0443 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B"</li>
  <li>\u041A\u043D\u043E\u043F\u043A\u0430 \u043F\u0435\u0440\u0435\u043C\u0438\u043A\u0430\u0447\u0430 "\u041A\u0456\u043B\u044C\u043A\u0456\u0441\u0442\u044C \u0441\u043B\u0456\u0432" \u0443 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B"</li>
  <li>\u041F\u043E\u0441\u0438\u043B\u0430\u043D\u043D\u044F \u043D\u0430 \u0431\u0440\u0435\u043D\u0434\u0438\u043D\u0433 \u0443 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B"</li>
  <li>\u041C\u0430\u0440\u043A\u0435\u0440 \u0437\u043C\u0456\u043D\u0435\u043D\u043D\u044F \u0440\u043E\u0437\u043C\u0456\u0440\u0443 \u0432 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B"</li>
</ol>

<p>\u042F\u043A\u0449\u043E \u0440\u043E\u0437\u0434\u0456\u043B \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u0432\u0456\u0434\u0441\u0443\u0442\u043D\u0456\u0439, \u0432\u0456\u043D \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0430\u0454\u0442\u044C\u0441\u044F.</p>

<p>\u042F\u043A\u0449\u043E \u0444\u043E\u043A\u0443\u0441 \u043D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u0457 \u043A\u043B\u0430\u0432\u0456\u0430\u0442\u0443\u0440\u0438 \u0437\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u043D\u0430 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B", \u0430\u043B\u0435 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447 \u043D\u0435 \u0431\u0430\u0447\u0438\u0442\u044C \u0432\u0438\u0434\u0438\u043C\u0443 \u0431\u0456\u0447\u043D\u0443 \u043F\u0430\u043D\u0435\u043B\u044C, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C <strong>Shift+Tab</strong>,
  \u0449\u043E\u0431 \u043F\u0435\u0440\u0435\u043C\u0456\u0441\u0442\u0438\u0442\u0438 \u0444\u043E\u043A\u0443\u0441 \u043D\u0430 \u043F\u0435\u0440\u0448\u0443 \u0433\u0440\u0443\u043F\u0443 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432, \u0430 \u043D\u0435 \u043D\u0430 \u043E\u0441\u0442\u0430\u043D\u043D\u044E.</p>

<h1>\u041D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u044F \u0432 \u043C\u0435\u0436\u0430\u0445 \u0440\u043E\u0437\u0434\u0456\u043B\u0456\u0432 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430</h1>

<p>\u0429\u043E\u0431 \u043F\u0435\u0440\u0435\u0439\u0442\u0438 \u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0443 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u0434\u043E \u043D\u0430\u0441\u0442\u0443\u043F\u043D\u043E\u0433\u043E, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0443 \u043A\u043B\u0430\u0432\u0456\u0448\u0443 <strong>\u0437\u0456 \u0441\u0442\u0440\u0456\u043B\u043A\u043E\u044E</strong>.</p>

<p>\u041A\u043B\u0430\u0432\u0456\u0448\u0456 \u0437\u0456 \u0441\u0442\u0440\u0456\u043B\u043A\u0430\u043C\u0438 <strong>\u041B\u0456\u0432\u043E\u0440\u0443\u0447</strong> \u0456 <strong>\u041F\u0440\u0430\u0432\u043E\u0440\u0443\u0447</strong></p>

<ul>
  <li>\u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u043C\u0456\u0436 \u043C\u0435\u043D\u044E \u0432 \u0440\u044F\u0434\u043A\u0443 \u043C\u0435\u043D\u044E.</li>
  <li>\u0432\u0456\u0434\u043A\u0440\u0438\u0432\u0430\u044E\u0442\u044C \u0432\u043A\u043B\u0430\u0434\u0435\u043D\u0435 \u043C\u0435\u043D\u044E \u0432 \u043C\u0435\u043D\u044E.</li>
  <li>\u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430 \u043C\u0456\u0436 \u043A\u043D\u043E\u043F\u043A\u0430\u043C\u0438 \u0432 \u0433\u0440\u0443\u043F\u0456 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432.</li>
  <li>\u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u043C\u0456\u0436 \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0432 \u0448\u043B\u044F\u0445\u0443 \u0434\u043E \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0456\u0432 \u0443 \u0440\u043E\u0437\u0434\u0456\u043B\u0456 "\u041D\u0438\u0436\u043D\u0456\u0439 \u043A\u043E\u043B\u043E\u043D\u0442\u0438\u0442\u0443\u043B".</li>
</ul>

<p>\u041A\u043B\u0430\u0432\u0456\u0448\u0456 \u0437\u0456 \u0441\u0442\u0440\u0456\u043B\u043A\u0430\u043C\u0438 <strong>\u0412\u043D\u0438\u0437</strong> \u0456 <strong>\u0412\u0433\u043E\u0440\u0443</strong></p>

<ul>
  <li>\u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u043C\u0456\u0436 \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u043C\u0435\u043D\u044E \u0432 \u043C\u0435\u043D\u044E.</li>
  <li>\u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u043C\u0456\u0436 \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0432 \u0441\u043F\u043B\u0438\u0432\u0430\u044E\u0447\u043E\u043C\u0443 \u043C\u0435\u043D\u044E \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432.</li>
</ul>

<p>\u041A\u043B\u0430\u0432\u0456\u0448\u0456 <strong>\u0437\u0456 \u0441\u0442\u0440\u0456\u043B\u043A\u0430\u043C\u0438</strong> \u043F\u0435\u0440\u0435\u043C\u0456\u0449\u0443\u044E\u0442\u044C \u0444\u043E\u043A\u0443\u0441 \u0446\u0438\u043A\u043B\u0456\u0447\u043D\u043E \u0432 \u043C\u0435\u0436\u0430\u0445 \u0440\u043E\u0437\u0434\u0456\u043B\u0443 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430, \u043D\u0430 \u044F\u043A\u043E\u043C\u0443 \u0437\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u0444\u043E\u043A\u0443\u0441.</p>

<p>\u0429\u043E\u0431 \u0437\u0430\u043A\u0440\u0438\u0442\u0438 \u0432\u0456\u0434\u043A\u0440\u0438\u0442\u0435 \u043C\u0435\u043D\u044E, \u0432\u0456\u0434\u043A\u0440\u0438\u0442\u0435 \u0432\u043A\u043B\u0430\u0434\u0435\u043D\u0435 \u043C\u0435\u043D\u044E \u0430\u0431\u043E \u0432\u0456\u0434\u043A\u0440\u0438\u0442\u0435 \u0441\u043F\u043B\u0438\u0432\u0430\u044E\u0447\u0435 \u043C\u0435\u043D\u044E, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u043A\u043B\u0430\u0432\u0456\u0448\u0443 <strong>Esc</strong>.</p>

<p>\u042F\u043A\u0449\u043E \u043F\u043E\u0442\u043E\u0447\u043D\u0438\u0439 \u0444\u043E\u043A\u0443\u0441 \u0437\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u043D\u0430 \u0432\u0435\u0440\u0445\u043D\u044C\u043E\u043C\u0443 \u0440\u0456\u0432\u043D\u0456 \u043F\u0435\u0432\u043D\u043E\u0433\u043E \u0440\u043E\u0437\u0434\u0456\u043B\u0443 \u0456\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0443 \u043A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430, \u043D\u0430\u0442\u0438\u0441\u043A\u0430\u043D\u043D\u044F \u043A\u043B\u0430\u0432\u0456\u0448\u0456 <strong>Esc</strong> \u0442\u0430\u043A\u043E\u0436 \u0432\u0438\u043A\u043E\u043D\u0443\u0454 \u0432\u0438\u0445\u0456\u0434
  \u0437 \u043D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u0457 \u0437\u0430 \u0434\u043E\u043F\u043E\u043C\u043E\u0433\u043E\u044E \u043A\u043B\u0430\u0432\u0456\u0430\u0442\u0443\u0440\u0438 \u043F\u043E\u0432\u043D\u0456\u0441\u0442\u044E.</p>

<h1>\u0412\u0438\u043A\u043E\u043D\u0430\u043D\u043D\u044F \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0443 \u043C\u0435\u043D\u044E \u0430\u0431\u043E \u043A\u043D\u043E\u043F\u043A\u0438 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432</h1>

<p>\u041A\u043E\u043B\u0438 \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u0438\u0439 \u0435\u043B\u0435\u043C\u0435\u043D\u0442 \u043C\u0435\u043D\u044E \u0430\u0431\u043E \u043A\u043D\u043E\u043F\u043A\u0443 \u043F\u0430\u043D\u0435\u043B\u0456 \u0456\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0456\u0432 \u0432\u0438\u0434\u0456\u043B\u0435\u043D\u043E, \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u043A\u043B\u0430\u0432\u0456\u0448\u0456 <strong>Return</strong>, <strong>Enter</strong>,
  \u0430\u0431\u043E <strong>\u041F\u0440\u043E\u0431\u0456\u043B</strong>, \u0449\u043E\u0431 \u0432\u0438\u043A\u043E\u043D\u0430\u0442\u0438 \u0446\u0435\u0439 \u0435\u043B\u0435\u043C\u0435\u043D\u0442.</p>

<h1>\u041D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u044F \u043F\u043E \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0438\u043C \u0432\u0456\u043A\u043D\u0430\u043C \u0431\u0435\u0437 \u0432\u043A\u043B\u0430\u0434\u043E\u043A</h1>

<p>\u0423 \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0438\u0445 \u0432\u0456\u043A\u043D\u0430\u0445 \u0431\u0435\u0437 \u0432\u043A\u043B\u0430\u0434\u043E\u043A \u043F\u0435\u0440\u0448\u0438\u0439 \u0456\u043D\u0442\u0435\u0440\u0430\u043A\u0442\u0438\u0432\u043D\u0438\u0439 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442 \u043F\u0440\u0438\u0439\u043C\u0430\u0454 \u0444\u043E\u043A\u0443\u0441, \u043A\u043E\u043B\u0438 \u0432\u0456\u0434\u043A\u0440\u0438\u0432\u0430\u0454\u0442\u044C\u0441\u044F \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0435 \u0432\u0456\u043A\u043D\u043E.</p>

<p>\u041F\u0435\u0440\u0435\u0445\u043E\u0434\u044C\u0442\u0435 \u043C\u0456\u0436 \u0456\u043D\u0442\u0435\u0440\u0430\u043A\u0442\u0438\u0432\u043D\u0438\u043C\u0438 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430\u043C\u0438 \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u043E\u0433\u043E \u0432\u0456\u043A\u043D\u0430, \u043D\u0430\u0442\u0438\u0441\u043A\u0430\u044E\u0447\u0438 \u043A\u043B\u0430\u0432\u0456\u0448\u0456 <strong>Tab</strong> \u0430\u0431\u043E <strong>Shift+Tab</strong>.</p>

<h1>\u041D\u0430\u0432\u0456\u0433\u0430\u0446\u0456\u044F \u043F\u043E \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0438\u043C \u0432\u0456\u043A\u043D\u0430\u043C \u0437 \u0432\u043A\u043B\u0430\u0434\u043A\u0430\u043C\u0438</h1>

<p>\u0423 \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0438\u0445 \u0432\u0456\u043A\u043D\u0430\u0445 \u0456\u0437 \u0432\u043A\u043B\u0430\u0434\u043A\u0430\u043C\u0438 \u043F\u0435\u0440\u0448\u0430 \u043A\u043D\u043E\u043F\u043A\u0430 \u0432 \u043C\u0435\u043D\u044E \u0432\u043A\u043B\u0430\u0434\u043A\u0438 \u043F\u0440\u0438\u0439\u043C\u0430\u0454 \u0444\u043E\u043A\u0443\u0441, \u043A\u043E\u043B\u0438 \u0432\u0456\u0434\u043A\u0440\u0438\u0432\u0430\u0454\u0442\u044C\u0441\u044F \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u0435 \u0432\u0456\u043A\u043D\u043E.</p>

<p>\u041F\u0435\u0440\u0435\u0445\u043E\u0434\u044C\u0442\u0435 \u043C\u0456\u0436 \u0456\u043D\u0442\u0435\u0440\u0430\u043A\u0442\u0438\u0432\u043D\u0438\u043C\u0438 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430\u043C\u0438 \u0446\u0456\u0454\u0457 \u0432\u043A\u043B\u0430\u0434\u043A\u0438 \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u043E\u0433\u043E \u0432\u0456\u043A\u043D\u0430, \u043D\u0430\u0442\u0438\u0441\u043A\u0430\u044E\u0447\u0438 \u043A\u043B\u0430\u0432\u0456\u0448\u0456 <strong>Tab</strong> \u0430\u0431\u043E
  <strong>Shift+Tab</strong>.</p>

<p>\u0429\u043E\u0431 \u043F\u0435\u0440\u0435\u0439\u0442\u0438 \u043D\u0430 \u0456\u043D\u0448\u0443 \u0432\u043A\u043B\u0430\u0434\u043A\u0443 \u0434\u0456\u0430\u043B\u043E\u0433\u043E\u0432\u043E\u0433\u043E \u0432\u0456\u043A\u043D\u0430, \u043F\u0435\u0440\u0435\u043C\u0456\u0441\u0442\u0456\u0442\u044C \u0444\u043E\u043A\u0443\u0441 \u043D\u0430 \u043C\u0435\u043D\u044E \u0432\u043A\u043B\u0430\u0434\u043A\u0438, \u0430 \u043F\u043E\u0442\u0456\u043C \u043D\u0430\u0442\u0438\u0441\u043D\u0456\u0442\u044C \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0443 \u043A\u043B\u0430\u0432\u0456\u0448\u0443 <strong>\u0437\u0456 \u0441\u0442\u0440\u0456\u043B\u043A\u043E\u044E</strong>,
  \u0449\u043E\u0431 \u0446\u0438\u043A\u043B\u0456\u0447\u043D\u043E \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0438\u0442\u0438 \u043F\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u0438\u043C \u0432\u043A\u043B\u0430\u0434\u043A\u0430\u043C.</p>
`);
